css:
@page {
  size: landscape;
}

.print-format {
  font-family: Arial, sans-serif;
  font-size: 11px;
  color: #333;
  padding: 10px;
}

.print-format .header-section {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 10px;
  border-bottom: 2px solid #333;
  padding-bottom: 10px;
}

.print-format .company-info {
  flex: 1;
}

.print-format .company-info h2 {
  margin: 0 0 5px 0;
  font-size: 18px;
  color: #222;
}

.print-format .doc-details {
  text-align: right;
}

.print-format .doc-details h3 {
  margin: 0 0 5px 0;
  font-size: 16px;
  color: #222;
}

.print-format .info-grid {
  display: flex;
  flex-wrap: wrap;
  gap: 15px;
  margin-bottom: 15px;
  padding: 10px;
  background: #f8f8f8;
  border-radius: 4px;
}

.print-format .info-block {
  flex: 1;
  min-width: 180px;
}

.print-format .info-block .label {
  font-size: 9px;
  text-transform: uppercase;
  color: #888;
  letter-spacing: 0.5px;
  margin-bottom: 2px;
}

.print-format .info-block .value {
  font-size: 11px;
  color: #333;
}

.print-format .address-block {
  margin-bottom: 15px;
}

.print-format .address-block .label {
  font-size: 9px;
  text-transform: uppercase;
  color: #888;
  letter-spacing: 0.5px;
  margin-bottom: 2px;
}

.print-format .items-table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 15px;
}

.print-format .items-table th {
  background: #f0f0f0;
  border: 1px solid #ccc;
  padding: 6px 8px;
  text-align: left;
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  color: #555;
}

.print-format .items-table td {
  border: 1px solid #ddd;
  padding: 6px 8px;
  font-size: 11px;
  vertical-align: middle;
}

.print-format .items-table td.number {
  text-align: right;
}

.print-format .items-table td img {
  max-height: 60px;
  max-width: 80px;
  display: block;
}

.print-format .items-table tr:nth-child(even) {
  background: #fafafa;
}

.print-format .totals-section {
  display: flex;
  justify-content: flex-end;
  margin-top: 15px;
}

.print-format .totals-table {
  width: 350px;
  border-collapse: collapse;
}

.print-format .totals-table td {
  padding: 4px 8px;
  font-size: 11px;
}

.print-format .totals-table td:first-child {
  text-align: right;
  font-weight: 600;
  color: #555;
}

.print-format .totals-table td:last-child {
  text-align: right;
  min-width: 120px;
}

.print-format .totals-table .grand-total td {
  font-size: 13px;
  font-weight: 700;
  color: #222;
  border-top: 2px solid #333;
  padding-top: 6px;
}

.print-format .in-words {
  margin-top: 10px;
  font-style: italic;
  color: #666;
  font-size: 10px;
}

.print-format .terms-section {
  margin-top: 20px;
  padding-top: 10px;
  border-top: 1px solid #ddd;
}

.print-format .terms-section h4 {
  font-size: 12px;
  margin: 0 0 5px 0;
  color: #333;
}

.print-format .terms-section .terms-content {
  font-size: 10px;
  color: #555;
  line-height: 1.4;
}
